using System;\nusing System.Threading.Tasks;\nusing zAjedrezServer.Network;\n\nnamespace zAjedrezServer\n{\n    /// <summary>\n    /// zAjedrezServer MAIN ENTRY POINT\n    /// PUSH application startup sequence\n    /// CALL TcpServer.Start() on port 5555\n    /// WAIT for incoming connections\n    /// MOV console listener active\n    /// </summary>\n    class Program\n    {\n        static async Task Main(string[] args)\n        {\n            Console.WriteLine(\"╔════════════════════════════════════════════════════════════╗\");\n            Console.WriteLine(\"║         🦊 zAjedrezServer - Chess Battle Engine 🦊          ║\");\n            Console.WriteLine(\"║                  [ZORRODEV EDITION v1.0]                    ║\");\n            Console.WriteLine(\"╚════════════════════════════════════════════════════════════╝\");\n            Console.WriteLine();\n\n            try\n            {\n                // PUSH server configuration\n                const int PORT = 5555;\n                Console.WriteLine($\"🔧 CONFIGURATION:\");\n                Console.WriteLine($\"   [PORT] .......... {PORT}\");\n                Console.WriteLine($\"   [STORAGE] ....... ./data/\");\n                Console.WriteLine($\"   [NETWORK] ....... TCP/IP (Xeon ready)\");\n                Console.WriteLine();\n\n                // INIT TCP Server\n                Console.WriteLine($\"⚙️  INITIALIZING SERVER...\");\n                var server = new TcpServer(PORT);\n                Console.WriteLine($\"✅ Server initialized on localhost:{PORT}\");\n                Console.WriteLine();\n\n                // PUSH banner\n                Console.WriteLine(\"┌────────────────────────────────────────────────────────────┐\");\n                Console.WriteLine(\"│ STATUS: [LISTENING FOR INCOMING CONNECTIONS]              │\");\n                Console.WriteLine(\"│ Commands:                                                  │\");\n                Console.WriteLine(\"│   JSON-RPC 2.0 protocol over TCP                          │\");\n                Console.WriteLine(\"│   Supported methods: CreateMatch, MakeMove, EndMatch      │\");\n                Console.WriteLine(\"│   AuthToken required for all requests                     │\");\n                Console.WriteLine(\"└────────────────────────────────────────────────────────────┘\");\n                Console.WriteLine();\n\n                // START listener loop\n                Console.WriteLine($\"🎯 AWAITING CONNECTIONS...\");\n                await server.StartAsync();\n            }\n            catch (Exception ex)\n            {\n                Console.ForegroundColor = ConsoleColor.Red;\n                Console.WriteLine($\"❌ FATAL ERROR: {ex.Message}\");\n                Console.WriteLine($\"STACK TRACE: {ex.StackTrace}\");\n                Console.ResetColor();\n                Environment.Exit(1);\n            }\n        }\n    }\n}\n